import type { SelectOption } from '@linm-soft-org/linm-web-common-components';

/** Tenant / company field — maps UI «Đơn vị cơ sở» to API `companyCode`. */
export const COMPANY_FIELD_LABEL = 'Đơn vị cơ sở';

export const COMPANY_PLACEHOLDER_OPTION: SelectOption = {
  value: '',
  label: '— Chọn đơn vị cơ sở —',
};

export function withCompanyPlaceholder(options: SelectOption[]): SelectOption[] {
  return [COMPANY_PLACEHOLDER_OPTION, ...options];
}

export type CompanyCode = string;

/** Fallback when company list not loaded yet — tenant key is company code (LINM, FM06). */
export function formatCompanyLabel(companyCode: string): string {
  return companyCode.trim().toUpperCase();
}

export interface HasCompanyCode {
  companyCode?: string;
}
