import { apiClient, unwrap, type BffResponse } from '../api';
import type {
  MasterCodeLegalEntityOptionDto,
  MasterCodeRegistrationDto,
  UpdateMasterCodeRegistrationDto,
} from './masterCodeModels';

const BASE = '/master/code-registrations';

export const HR_EMPLOYEES_CATALOG_KIND = 'hr-employees';

export interface MasterCodeFormatPreviewDto {
  catalogKind: string;
  prefix: string;
  formatPreview: string;
  autoGenerate: boolean;
}

export const masterCodeService = {
  getList: async (): Promise<MasterCodeRegistrationDto[]> => {
    const res = await apiClient.get<BffResponse<MasterCodeRegistrationDto[]>>(BASE);
    return unwrap(res);
  },

  getLegalEntityOptions: async (): Promise<MasterCodeLegalEntityOptionDto[]> => {
    const res = await apiClient.get<BffResponse<MasterCodeLegalEntityOptionDto[]>>(
      `${BASE}/legal-entity-options`,
    );
    return unwrap(res);
  },

  getFormatPreview: async (catalogKind: string): Promise<MasterCodeFormatPreviewDto> => {
    const res = await apiClient.get<BffResponse<MasterCodeFormatPreviewDto>>(
      `${BASE}/by-kind/${encodeURIComponent(catalogKind)}/format-preview`,
    );
    return unwrap(res);
  },

  getByKind: async (catalogKind: string): Promise<MasterCodeRegistrationDto> => {
    const res = await apiClient.get<BffResponse<MasterCodeRegistrationDto>>(
      `${BASE}/by-kind/${encodeURIComponent(catalogKind)}`,
    );
    return unwrap(res);
  },

  update: async (
    id: string,
    body: UpdateMasterCodeRegistrationDto,
  ): Promise<MasterCodeRegistrationDto> => {
    const res = await apiClient.put<BffResponse<MasterCodeRegistrationDto>>(
      `${BASE}/${encodeURIComponent(id)}`,
      body,
    );
    return unwrap(res);
  },
};
