import { useEffect, useMemo, useState } from 'react';
import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { catalogUiSchemaService } from '../../../services/catalog/catalogUiSchemaService';
import type { CatalogUiSchema } from '../../../types/catalogUiSchema';
import {
  mapCatalogSchemaToSearchConfig,
  type CatalogSearchAdapter,
} from './mapCatalogSchemaToSearchConfig';

/**
 * Load ui-schema once and memo SearchInputConfig — lookup columns from config.
 */
export function useCatalogSearchConfig<T extends Record<string, unknown>>(
  catalogKind: string,
  search: CatalogSearchAdapter<T>,
  getItemKey: (item: T) => string,
  display?: {
    getPrimaryDisplay?: (item: T) => string;
    getSecondaryDisplay?: (item: T) => string;
  },
): { config: SearchInputConfig<T> | null; schema: CatalogUiSchema | null; loading: boolean } {
  const [schema, setSchema] = useState<CatalogUiSchema | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    catalogUiSchemaService
      .get(catalogKind, false)
      .then(data => { if (!cancelled) setSchema(data); })
      .catch(() => { if (!cancelled) setSchema(null); })
      .finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [catalogKind]);

  const config = useMemo(() => {
    if (!schema) return null;
    return mapCatalogSchemaToSearchConfig(schema, {
      search,
      getItemKey,
      getPrimaryDisplay: display?.getPrimaryDisplay,
      getSecondaryDisplay: display?.getSecondaryDisplay,
    });
  }, [schema, search, getItemKey, display?.getPrimaryDisplay, display?.getSecondaryDisplay]);

  return { config, schema, loading };
}
