export function getSharedCatalogProposalFields(catalogKind: string): SharedCatalogProposalFieldDef[] {
  return REGISTRY[catalogKind] ?? [
    { key: 'name', label: 'Tên', type: 'text' },
    { key: 'isActive', label: 'Đang sử dụng', type: 'boolean' },
  ];
}

export interface ProposalFieldControlProps {
  def: SharedCatalogProposalFieldDef;
  value: unknown;
  disabled?: boolean;
  hideLabel?: boolean;
  testIdPrefix: string;
  onChange: (key: string, value: unknown) => void;
}

export function SharedCatalogProposalFieldControl({
  def,
  value,
  disabled,
  hideLabel,
  testIdPrefix,
  onChange,
}: ProposalFieldControlProps): React.ReactElement {
  if (def.type === 'boolean') {
    return (
      <Checkbox
        label={hideLabel ? '' : def.label}
        checked={!!value}
        disabled={disabled}
        data-testid={`${testIdPrefix}-proposal-field-${def.key}`}
        onChange={e => onChange(def.key, e.target.checked)}
      />
    );
  }
  return (
    <Input
      label={hideLabel ? undefined : def.label}
      value={value == null ? '' : String(value)}
      disabled={disabled}
      data-testid={`${testIdPrefix}-proposal-field-${def.key}`}
      onChange={e => onChange(def.key, e.target.value)}
    />
  );
}
