import type {
  SharedCatalogChangeRequestDto,
  SharedCatalogMetaDto,
  SharedCatalogUsageDto,
} from './models';

/** HR tenant catalogs — shared master API stubs (unused when `shared` omitted). */
export const masterService = {
  getSharedCatalogMeta: async (_catalogKind: string): Promise<SharedCatalogMetaDto | null> => null,
  requestSharedCatalogUsage: async (_catalogKind: string, _note?: string): Promise<void> => {},
  createSharedCatalogChangeRequest: async (_body: {
    catalogKind: string;
    action: string;
    entityKey: string;
    payloadJson?: string;
  }): Promise<void> => {},
  listSharedCatalogUsageRequests: async (
    _catalogKind: string,
    _status = 'Pending',
  ): Promise<SharedCatalogUsageDto[]> => [],
  listSharedCatalogChangeRequests: async (
    _catalogKind: string,
    _status = 'Pending',
  ): Promise<SharedCatalogChangeRequestDto[]> => [],
  approveSharedCatalogUsage: async (_id: string, _note?: string): Promise<SharedCatalogUsageDto> => {
    throw new Error('Shared catalog not supported in HR MFE');
  },
  rejectSharedCatalogUsage: async (_id: string, _note?: string): Promise<SharedCatalogUsageDto> => {
    throw new Error('Shared catalog not supported in HR MFE');
  },
  approveSharedCatalogChange: async (
    _id: string,
    _note?: string,
  ): Promise<SharedCatalogChangeRequestDto> => {
    throw new Error('Shared catalog not supported in HR MFE');
  },
  rejectSharedCatalogChange: async (
    _id: string,
    _note?: string,
  ): Promise<SharedCatalogChangeRequestDto> => {
    throw new Error('Shared catalog not supported in HR MFE');
  },
};
